var browserify = require('browserify');
var proxyquire = require('proxyquireify');
const tsify = require('tsify');
const fs = require('fs');

browserify()
    .require('./index.ts', {
        expose: 'ytdl-core-browser'
    })
    .plugin(tsify, {
        declaration: true,
        declarationMap: true,
        sourceMap: true
    })
    .plugin(proxyquire.plugin)
    .bundle()
    .pipe(fs.createWriteStream('./dist/index.js'));